import React, { useEffect, useState } from "react";

import { getAllVariants } from "../services/ApiService";

function Home() {

    const [variants, setVariants] = useState([]);

    useEffect(() => {

        loadVariants();

    }, []);

    const loadVariants = async () => {

        try {

            const response = await getAllVariants();

            console.log(response.data);

            setVariants(response.data);

        } catch (error) {

            console.log(error);

        }
    };

    return (

        <div style={{padding: "20px"}}>

            <h1>All Car Variants</h1>

            {
                variants.map((variant) => (

                    <div
                        key={variant.id}

                        style={{
                            border: "1px solid black",
                            marginBottom: "20px",
                            padding: "10px"
                        }}
                    >

                        <h2>{variant.variantName}</h2>

                        <p>
                            Company :
                            {variant.carCompany.companyName}
                        </p>

                        <p>
                            Fuel Type :
                            {variant.fuelType}
                        </p>

                        <p>
                            Price :
                            {variant.pricePerDay}
                        </p>

                        <button>

                            Book Now

                        </button>

                    </div>
                ))
            }

        </div>
    );
}

export default Home;
